#!/usr/bin/env python3
"""
Composite Indicator

综合打分指标 — 加权平均所有子指标
"""

from typing import Any, Dict, List

from .base import (
    BaseIndicator, IndicatorResult, MarketSignal,
    get_indicator, list_indicators, register_indicator,
)

# 指标权重配置
# 链上 40%: MVRV(12%) + Netflow(10%) + NUPL(10%) + Puell(8%)
# 市场结构 25%: AHR999(10%) + Pi Cycle(8%) + BTC.D(7%)
# 衍生品 20%: Funding(10%) + OI(10%)
# 情绪 15%: Fear&Greed(8%) + 稳定币(7%)
WEIGHTS = {
    "mvrv": 0.12,
    "exchange_netflow": 0.10,
    "nupl": 0.10,
    "puell_multiple": 0.08,
    "ahr999": 0.10,
    "pi_cycle_top": 0.08,
    "btc_dominance": 0.07,
    "funding_rate": 0.10,
    "open_interest": 0.10,
    "fear_greed": 0.08,
    "stablecoin_supply": 0.07,
}


class MarketScoreIndicator(BaseIndicator):
    """综合市场评分

    加权平均所有子指标:
      0.0-0.3 = 深熊（抄底区）
      0.3-0.5 = 早期复苏
      0.5-0.7 = 牛市
      0.7-0.9 = 牛市后期（止盈区）
      0.9-1.0 = 狂热（逃顶）
    """

    name = "market_score"
    source = "composite"

    def fetch(self, **kwargs) -> Dict:
        results = {}
        failed = []
        available = list_indicators()

        for ind_name, weight in WEIGHTS.items():
            if ind_name not in available:
                failed.append(ind_name)
                continue
            try:
                indicator = get_indicator(ind_name)
                result = indicator.evaluate(**kwargs)
                if result.ok:
                    results[ind_name] = {
                        "score": result.score,
                        "weight": weight,
                        "raw": result.raw_value,
                    }
                else:
                    failed.append(ind_name)
            except Exception:
                failed.append(ind_name)

        return {"results": results, "failed": failed}

    def score(self, raw_value: Dict) -> float:
        results = raw_value["results"]
        if not results:
            return 0.5  # 全部失败，返回中性

        # 按比例重分配权重（排除失败的）
        total_weight = sum(r["weight"] for r in results.values())
        if total_weight == 0:
            return 0.5

        weighted_sum = sum(
            r["score"] * (r["weight"] / total_weight)
            for r in results.values()
        )
        return round(weighted_sum, 4)

    def signal(self, score_value: float) -> MarketSignal:
        if score_value >= 0.8:
            return MarketSignal.STRONG_BUY
        elif score_value >= 0.6:
            return MarketSignal.BUY
        elif score_value >= 0.4:
            return MarketSignal.NEUTRAL
        elif score_value >= 0.2:
            return MarketSignal.SELL
        else:
            return MarketSignal.STRONG_SELL

    def evaluate(self, **kwargs) -> IndicatorResult:
        """覆盖基类，附加详细信息"""
        try:
            raw = self.fetch(**kwargs)
            s = self.score(raw)
            sig = self.signal(s)
            n_ok = len(raw["results"])
            n_fail = len(raw["failed"])
            info = f"{n_ok}/{n_ok + n_fail} 指标可用"
            if raw["failed"]:
                info += f"，失败: {', '.join(raw['failed'])}"
            return IndicatorResult(
                name=self.name,
                raw_value=raw,
                score=s,
                signal=sig,
                source=self.source,
                info=info,
            )
        except Exception as e:
            return IndicatorResult(
                name=self.name,
                score=0.5,
                signal=MarketSignal.NEUTRAL,
                source=self.source,
                error=str(e),
            )


register_indicator("market_score", MarketScoreIndicator)


__all__ = ['MarketScoreIndicator', 'WEIGHTS']

#!/usr/bin/env python3
"""
Strategy Package

策略包
自动扫描并导入所有策略
"""

from .base import Strategy, Signal, TradingSignal, register_strategy, get_strategy, list_strategies

__all__ = ['Strategy', 'Signal', 'TradingSignal', 'register_strategy', 'get_strategy', 'list_strategies']

import pkgutil
from pathlib import Path
import sys

_CURRENT_DIR = Path(__file__).parent

# 自动扫描所有模块
_modules = []
for module_info in pkgutil.iter_modules([str(_CURRENT_DIR)]):
    module_name = module_info.name
    if not module_name.startswith('_') and not module_name == 'base':
        _modules.append(module_name)

__all__ += _modules

# 延迟导入所有模块
for module_name in _modules:
    try:
        exec(f"from .{module_name} import *")
    except Exception as e:
        pass

# 自动注册所有 Strategy 子类
from .base import _STRATEGY_REGISTRY

for module_name in _modules:
    try:
        full_module_name = f'core.strategy.{module_name}'
        if full_module_name not in sys.modules:
            __import__(full_module_name)

        mod = sys.modules.get(full_module_name)
        if mod:
            for attr_name in dir(mod):
                attr = getattr(mod, attr_name)
                if isinstance(attr, type) and issubclass(attr, Strategy) and attr is not Strategy:
                    # 自动从类名生成策略名
                    # 特殊处理：MA -> ma, RSI -> rsi 等
                    strategy_name = attr_name
                    # 去掉常见后缀
                    for suffix in ['Strategy', '_']:
                        if strategy_name.endswith(suffix):
                            strategy_name = strategy_name[:-len(suffix)]
                    # 转换为小写
                    strategy_name = strategy_name.lower()
                    if strategy_name not in _STRATEGY_REGISTRY:
                        register_strategy(strategy_name, attr)
    except Exception as e:
        pass  # 忽略错误

#!/usr/bin/env python3
"""
Abby Autonomy - 状态检查

检查任务状态和紧急事项
"""

import json
import os
from pathlib import Path
from datetime import datetime
from typing import Dict, Optional


# 状态文件路径
STATE_FILE = Path(__file__).parent.parent / "memory" / "task_state.json"


class TaskState:
    """任务状态追踪"""

    def __init__(self, state_file: str = None):
        self.state_file = state_file or str(STATE_FILE)

    def get_state(self) -> Dict:
        """获取当前状态"""
        if not os.path.exists(self.state_file):
            return {
                "current_task": None,
                "task_status": None,
                "estimated_completion": None,
                "progress": None,
                "started_at": None
            }

        try:
            with open(self.state_file) as f:
                return json.load(f)
        except Exception:
            return {
                "current_task": None,
                "task_status": None,
                "estimated_completion": None,
                "progress": None,
                "started_at": None
            }

    def set_state(self, state: Dict) -> bool:
        """设置状态"""
        try:
            os.makedirs(os.path.dirname(self.state_file), exist_ok=True)
            with open(self.state_file, 'w') as f:
                json.dump(state, f, indent=2)
            return True
        except Exception:
            return False

    def start_task(self, task: str, estimated_minutes: int = 30) -> bool:
        """
        开始任务

        Args:
            task: 任务内容
            estimated_minutes: 预计完成时间

        Returns:
            bool: 是否成功
        """
        now = datetime.now()
        # 计算预计完成时间
        completion = now.fromtimestamp(now.timestamp() + estimated_minutes * 60)

        state = {
            "current_task": task,
            "task_status": "running",
            "estimated_completion": completion.strftime('%Y-%m-%d %H:%M'),
            "progress": "0%",
            "started_at": now.strftime('%Y-%m-%d %H:%M:%S')
        }

        return self.set_state(state)

    def update_progress(self, progress: str) -> bool:
        """更新进度"""
        state = self.get_state()
        if state.get('task_status') == 'running':
            state['progress'] = progress
            return self.set_state(state)
        return False

    def complete_task(self) -> bool:
        """完成任务"""
        return self.set_state({
            "current_task": None,
            "task_status": None,
            "estimated_completion": None,
            "progress": None,
            "started_at": None
        })

    def has_running_task(self) -> bool:
        """是否有正在执行的任务"""
        state = self.get_state()
        return state.get('task_status') == 'running'

    def get_current_task(self) -> Optional[str]:
        """获取当前任务"""
        state = self.get_state()
        return state.get('current_task')


# 全局状态检查
_state = None


def has_running_task() -> bool:
    """检查是否有正在执行的任务"""
    global _state
    if _state is None:
        _state = TaskState()
    return _state.has_running_task()


def get_current_task() -> Optional[str]:
    """获取当前任务"""
    global _state
    if _state is None:
        _state = TaskState()
    return _state.get_current_task()


def start_task(task: str, estimated_minutes: int = 30) -> bool:
    """开始任务"""
    global _state
    if _state is None:
        _state = TaskState()
    return _state.start_task(task, estimated_minutes)


def update_progress(progress: str) -> bool:
    """更新进度"""
    global _state
    if _state is None:
        _state = TaskState()
    return _state.update_progress(progress)


def complete_task() -> bool:
    """完成任务"""
    global _state
    if _state is None:
        _state = TaskState()
    return _state.complete_task()
